head.script:
scwin.saveRow = 0;
scwin.alloccarBranCd = "";
scwin.clntNo = "";
scwin.clntNm = "";
scwin.ctrtNo = "";
scwin.eqKndCd = "";
scwin.trfClsCd = "";
scwin.vCurDate = "";
scwin.createFlag = true;

scwin.dataSetDebug = async function(dataList, isDebug) {
    if (isDebug == true) {
        let obj = dataList;
        let str = "[[[[" + obj.getID() + "]]]]]\n";
        for (let dsRow = 0; dsRow < obj.getRowCount(); dsRow++) {
            let colInfos = obj.getColumnIDs();
            for (let dsCol = 0; dsCol < colInfos.length; dsCol++) {
                str += "[" + colInfos[dsCol] + "] " + obj.getCellData(dsRow, colInfos[dsCol]) + ", ";
            }
            str += "\n\n";
        }
        await $c.win.alert(str);
    }
};

scwin.onpageload = async function() {
    scwin.createFlag = true;
    scwin.vCurDate = WebSquare.date.getCurrentServerDate("yyyyMMdd");

    scwin.params = $c.data.getParameter();
    if (scwin.params != null) {
        scwin.alloccarBranCd = scwin.params.lobranCd || "";
        scwin.clntNo = scwin.params.clntNo || "";
        scwin.clntNm = scwin.params.clntNm || "";
        scwin.ctrtNo = scwin.params.ctrtNo || "";
        scwin.eqKndCd = scwin.params.eqKndCd || "";
        scwin.trfClsCd = scwin.params.trfClsCd || "";
    }

    scwin.f_loadLobran();
};

scwin.f_loadLobran = async function() {
    await $c.sbm.execute(sbm_lobran);
};

scwin.sbm_lobran_submitdone = async function(e) {
    scwin.f_InitSrchCond();
    scwin.f_retrieve();
};

scwin.sbm_lobran_submiterror = async function(e) {
    $c.gus.cfShowError(e);
};

scwin.onUdcCompleted = function() {
    $c.gus.cfDisableObjects([ed_clntNo, txt_clntNm]);
};

scwin.f_InitSrchCond = async function() {
    if (!$c.gus.cfIsNull(scwin.alloccarBranCd)) {
        acb_alloccarBranCd.setValue(scwin.alloccarBranCd);
    }

    if (!$c.gus.cfIsNull(scwin.clntNm)) {
        txt_clntNm.setValue(scwin.clntNm);
    }

    if (!$c.gus.cfIsNull(scwin.eqKndCd)) {
        acb_eqKndCd.setValue(scwin.eqKndCd);
    } else {
        acb_eqKndCd.setValue("CT");
    }

    if (!$c.gus.cfIsNull(scwin.trfClsCd)) {
        acb_trfClsCd.setValue(scwin.trfClsCd);
    } else {
        acb_trfClsCd.setSelectedIndex(0);
    }

    $c.gus.cfInitHidVal([ed_clntNo, txt_clntNm]);

    if (!$c.gus.cfIsNull(scwin.clntNo)) {
        ed_clntNo.setValue(scwin.clntNo);
        scwin.f_retrieveCtrt(scwin.clntNo);
        if (!$c.gus.cfIsNull(scwin.ctrtNo)) {
            acb_ctrtNo.setValue(scwin.ctrtNo);
        }
    }
};

scwin.f_retrieve = async function() {
    if (await $c.gus.cfValidate([tbl_search]) == false) return false;

    if (acb_ctrtNo.getValue() == "선택" || $c.gus.cfIsNull(acb_ctrtNo.getValue())) {
        await $c.gus.cfAlertMsg("계약번호를 선택하십시오.");
        acb_ctrtNo.setFocus();
        return false;
    }

    ds_detail.removeAll();
    scwin.f_ProcessBinding_search();
    await $c.sbm.execute(sbm_retrieve);
};

scwin.f_ProcessBinding_search = function() {
    dma_search.set("alloccarBranCd", acb_alloccarBranCd.getValue());
    dma_search.set("clntNo", ed_clntNo.getValue().trim());
    dma_search.set("clntNm", txt_clntNm.getValue().trim());
    dma_search.set("ctrtNo", acb_ctrtNo.getValue());
    dma_search.set("trfClsCd", acb_trfClsCd.getValue());
    dma_search.set("eqKndCd", acb_eqKndCd.getValue());
    dma_search.set("comnTpchsTrf", chb_comnTpchsTrf.getValue());
};

scwin.f_retrieveDtl = async function() {
    let row = ds_master.getRowPosition();
    if (row < 0) return;

    let colNames = scwin.f_GetColumnNames_dma(dma_searchDtl);
    for (let c = 0; c < colNames.length; c++) {
        let colId = colNames[c];
        let val = ds_master.getCellData(row, colId);
        if (val != null && val !== undefined) {
            dma_searchDtl.set(colId, val);
        }
    }
    await $c.sbm.execute(sbm_retrieveDtl);
};

scwin.f_GetColumnNames_dma = function(dma) {
    let keys = dma.getKeyIDs();
    return keys;
};

scwin.f_retrieveCtrt = async function(clntNo) {
    dma_ctrtSrchCond.set("ctrtClntNo", clntNo);
    dma_ctrtSrchCond.set("ctrtCheck", "0");
    dma_ctrtSrchCond.set("ctrtDtYn", "1");

    await $c.sbm.execute(sbm_ctrt);
};

scwin.f_save = async function() {
    let masterRow = ds_master.getRowPosition();
    if (masterRow < 0) return false;

    if (ds_master.getRowStatus(masterRow) != "C" && scwin.f_IsUpdated([ds_detail]) == false) {
        await $c.gus.cfAlertMsg("변경된 사항이 없습니다.");
        return false;
    }

    let isAllZero = true;
    for (let i = 0; i < ds_detail.getRowCount(); i++) {
        if (ds_detail.getCellData(i, "pchsAmt") != 0) {
            isAllZero = false;
            break;
        }
    }

    if (isAllZero) {
        await $c.gus.cfAlertMsg("모든 요율이 0 입니다. 요율을 확인하십시오.");
        return false;
    }

    if (ds_master.getCellData(masterRow, "wrkStHh") == "" || ds_master.getCellData(masterRow, "wrkEndHh") == "") {
        await $c.gus.cfAlertMsg("적용구간을 확인해 주세요");
        return false;
    }

    if ((ds_master.getCellData(masterRow, "wrkUnitCd") == "VOT" || ds_master.getCellData(masterRow, "wrkUnitCd") == "VOC")
        && parseInt(ds_master.getCellData(masterRow, "wrkStHh")) >= parseInt(ds_master.getCellData(masterRow, "wrkEndHh"))) {
        await $c.gus.cfAlertMsg("적용구간MIN을 확인해 주세요");
        gr_master.setFocusedCell(masterRow, "wrkStHh");
        return false;
    }

    for (let i = 0; i < ds_detail.getRowCount(); i++) {
        if (ds_master.getRowStatus(masterRow) == "C") {
            await scwin.f_CopyDataRow2(ds_master, ds_detail, masterRow, i,
                ["trfClsCd", "ctrtNo", "adptDt", "alloccarBranCd", "eqKndCd", "odrKndCd",
                 "dptDistrictCd", "arvDistrictCd", "commCd", "wrkUnitCd", "copCoClntNo", "wrkStHh", "wrkEndHh"]);
        }
    }

    await scwin.dataSetDebug(ds_detail, false);

    let chk = await $c.win.confirm("저장하시겠습니까?");
    if (chk) {
        scwin.saveRow = ds_master.getRowPosition();
        await $c.sbm.execute(sbm_save);
    }
};

scwin.f_CopyDataRow2 = async function(sourceDataset, targetDataset, sourceRow, targetRow, sourceColumns, targetColumns, actionAfterRowAdded) {
    try {
        if (sourceDataset == null) throw "원본 데이터셋이 정의되지 않았습니다.";
        if (targetDataset == null) throw "대상 데이터셋이 정의되지 않았습니다.";

        if (sourceColumns == null) sourceColumns = scwin.f_GetColumnNames_dl(sourceDataset);
        if (targetColumns == null) targetColumns = sourceColumns;
        if (sourceRow == null) sourceRow = sourceDataset.getRowPosition();

        for (let i = 0; i < sourceColumns.length; i++) {
            if ($c.gus.cfIsNull(sourceColumns[i]) || $c.gus.cfIsNull(targetColumns[i])) continue;
            let val = sourceDataset.getCellData(sourceRow, sourceColumns[i]);
            targetDataset.setCellData(targetRow, targetColumns[i], val);
        }
        return targetRow;
    } catch (e) {
        await $c.gus.cfAlertMsg("[f_CopyDataRow2]" + e);
    }
};

scwin.f_CopyRow = async function() {
    if (scwin.f_IsUpdated([ds_master, ds_detail])) {
        await $c.gus.cfAlertMsg("변경된 사항이 있습니다. 저장 후 계속하십시오.");
        return false;
    }

    if (ds_master.getRowCount() > 0) {
        let srcRow = ds_master.getRowPosition();
        await scwin.f_CopyDataRow(ds_master, ds_master, srcRow, null,
            ["trfClsCd", "ctrtNo", "alloccarBranCd", "eqKndCd", "odrKndCd", "dptDistrictCd",
             "dptDistrictCd", "dptDistrictNm", "arvDistrictCd", "arvDistrictNm", "commCd", "commNm",
             "wrkUnitCd", "copCoClntNo", "copCoClntNm", "wrkStHh", "wrkEndHh"]);
        ds_master.setCellData(ds_master.getRowPosition(), "adptDt", scwin.vCurDate);
        $c.gus.cfPrepareHidVal(ds_master, ds_master.getRowPosition(), scwin.f_GetGridColumns(gr_master));
        scwin.f_retrieveDtl();
    } else {
        scwin.f_AddRow();
    }
};

scwin.f_AddRow = async function() {
    if (scwin.f_IsUpdated([ds_master, ds_detail])) {
        await $c.gus.cfAlertMsg("변경된 사항이 있습니다. 저장 후 계속하십시오.");
        return false;
    }

    let newRow = ds_master.insertRow();
    ds_master.setCellData(newRow, "alloccarBranCd", acb_alloccarBranCd.getValue());
    ds_master.setCellData(newRow, "eqKndCd", acb_eqKndCd.getValue());
    ds_master.setCellData(newRow, "ctrtNo", acb_ctrtNo.getValue());
    ds_master.setCellData(newRow, "trfClsCd", "01");
    ds_master.setCellData(newRow, "wrkStHh", "0");
    ds_master.setCellData(newRow, "odrKndCd", "99");
    ds_master.setCellData(newRow, "adptDt", scwin.vCurDate);
    ds_master.setCellData(newRow, "copCoClntNo", "999999");
    ds_master.setCellData(newRow, "copCoClntNm", "전체");
    ds_master.setCellData(newRow, "wrkStHh", "0");
    ds_master.setCellData(newRow, "wrkEndHh", "0");

    $c.gus.cfPrepareHidVal(ds_master, ds_master.getRowPosition(), scwin.f_GetGridColumns(gr_master));
    scwin.f_retrieveDtl();
};

scwin.f_DeleteRow = function() {
    let row = ds_master.getRowPosition();
    if (row < 0) return;

    ds_master.removeRow(row);

    let curRow = ds_master.getRowPosition();
    if (curRow >= 0 && ds_master.getRowStatus(curRow) == "C") return;

    for (let i = ds_detail.getRowCount() - 1; i >= 0; i--) {
        ds_detail.removeRow(i);
    }
};

scwin.f_CancelRow = function() {
    ds_detail.undoAll();
    let row = ds_master.getRowPosition();
    if (row >= 0) {
        ds_master.undoRow(row);
    }
};

scwin.f_DeleteDtlRow = async function() {
    let masterRow = ds_master.getRowPosition();
    if (masterRow >= 0 && ds_master.getRowStatus(masterRow) == "C") {
        await $c.gus.cfAlertMsg("신규 추가된 요율은 삭제할 수 없습니다.");
        return;
    }

    let dtlRow = ds_detail.getRowPosition();
    if (dtlRow < 0) return;

    if (ds_detail.getCellData(dtlRow, "pchsAmt") == 0 && ds_detail.getRowStatus(dtlRow) == "R") {
        await $c.gus.cfAlertMsg("지정된 요율이 없습니다.");
        return;
    }

    ds_detail.removeRow(dtlRow);
};

scwin.f_CancelDtlRow = function() {
    let row = ds_detail.getRowPosition();
    if (row >= 0) {
        ds_detail.undoRow(row);
    }
};

scwin.f_openBilgMchtPopUp = async function(pClose) {
    let codeObj = ed_clntNo;
    let nameObj = txt_clntNm;

    if (pClose == 'T' && $c.gus.cfCanOpenPopup(codeObj, nameObj) == false) {
        if ($c.gus.cfIsNull($c.gus.cfGetValue(codeObj))) {
            ds_ctrt.removeAll();
        }
        return;
    }

    let paramObj = {};
    paramObj.pSelectID = 'retrieveBilgMchtList_tpro';
    paramObj.pCode = $c.gus.cfGetValue(codeObj);
    paramObj.pName = $c.gus.cfGetValue(nameObj);
    paramObj.pWinCloseTF = pClose;
    paramObj.pAllSearchTF = 'F';
    paramObj.pWtitleSearch = "화주,화주코드/화주명";

    udc_clnt.ilCommonPopUp(scwin.callbackBilgMcht,
        paramObj.pCode, paramObj.pName,
        paramObj.pWinCloseTF, '2', '화주코드,화주명', '130,300',
        "", null, '500', '500', null, null, null,
        paramObj.pAllSearchTF, paramObj.pWtitleSearch, 'F');
};

scwin.callbackBilgMcht = async function(rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_clntNo, txt_clntNm);

    if (rtnList != null && rtnList[0] != "N/A") {
        scwin.f_retrieveCtrt(rtnList[0]);
    }

    chb_comnTpchsTrf.setValue("");
    acb_ctrtNo.setDisabled(false);
};

scwin.f_ToggleComnTpchsTrf = function() {
    let isChecked = (chb_comnTpchsTrf.getValue() != "" && chb_comnTpchsTrf.getValue() != null);

    if (isChecked) {
        let newRow = ds_ctrt.insertRow();
        ds_ctrt.setCellData(newRow, "ctrtNo", "99999999999");
        ds_ctrt.setCellData(newRow, "clntPicNm", "");
        ds_ctrt.setCellData(newRow, "ctrtStDt", "");
        ds_ctrt.setCellData(newRow, "ctrtEndDt", "");
        ds_ctrt.setCellData(newRow, "empNm", "");
        ds_ctrt.setCellData(newRow, "rmk", "");
        acb_ctrtNo.setSelectedIndex(ds_ctrt.getRowCount() - 1);

        acb_ctrtNo.setDisabled(true);
        ed_clntNo.setDisabled(true);
        txt_clntNm.setReadOnly(true);

        $c.gus.cfDisableObjects([udc_clnt]);
    } else {
        ds_ctrt.undoAll();
        acb_ctrtNo.setSelectedIndex(0);

        acb_ctrtNo.setDisabled(false);
        ed_clntNo.setDisabled(false);
        txt_clntNm.setReadOnly(false);

        $c.gus.cfEnableObjects([udc_clnt]);
    }
};

scwin.f_districtGridPopUp = async function(dataList, pWinCloseTF, pAllSearchTF, colid, colArray) {
    let row = dataList.getRowPosition();
    if (row < 0) return;

    let newData = dataList.getCellData(row, colid);
    let oldData = scwin.f_GetGridHidden(dataList, row, colid);

    if (pWinCloseTF == "T") {
        if (!scwin.f_CanGridPopup(dataList, colid, newData, oldData, colArray)) return false;
    }

    let pWhere = "";
    let isChecked = (chb_comnTpchsTrf.getValue() != "" && chb_comnTpchsTrf.getValue() != null);
    if (isChecked) {
        pWhere = ",,WDE";
    } else {
        if ($c.gus.cfIsNull(acb_ctrtNo.getValue())) {
            await $c.gus.cfAlertMsg("계약서번호를 선택하세요");
            acb_ctrtNo.setFocus();
            return;
        } else {
            pWhere = ",," + acb_ctrtNo.getValue();
        }
    }

    let paramObj = {};
    paramObj.pSelectID = "retrieveDistrictList2_tpro";
    paramObj.pCode = newData;
    paramObj.pWinCloseTF = pWinCloseTF;
    paramObj.pAllSearchTF = pAllSearchTF;
    paramObj.pWhere = pWhere;
    paramObj.pWtitleSearch = "권역조회,권역코드/권역명";

    // TODO: cfCommonPopUpEx 팝업 호출 - WebSquare 팝업 방식으로 전환 필요
    let rtnList = $c.gus.cfCommonPopUpEx(paramObj);
    await scwin.f_SetGridReturnValue(rtnList, dataList, row, colArray);
};

scwin.f_ExistSameRowYn = function(dataList, colArray) {
    if (dataList == null || colArray == null) return false;
    if (dataList.getRowCount() <= 1) return false;

    for (let i = 0; i < dataList.getRowCount() - 1; i++) {
        for (let j = i + 1; j < dataList.getRowCount(); j++) {
            if (i == j) continue;
            if (scwin.f_getRowDataStr(dataList, i, colArray) == scwin.f_getRowDataStr(dataList, j, colArray)) {
                return true;
            }
        }
    }
    return false;
};

scwin.f_getRowDataStr = function(dataList, row, colArray) {
    if (dataList == null || colArray == null || row == null) return "";
    if (!scwin.f_IsArray(colArray)) return "";
    if (row < 0) return "";

    let retArray = [];
    for (let i = 0; i < colArray.length; i++) {
        retArray[retArray.length] = dataList.getCellData(row, colArray[i]);
    }
    return retArray.toString();
};

scwin.f_commGridPopUp = async function(dataList, pWinCloseTF, pAllSearchTF, colid, colArray) {
    let row = dataList.getRowPosition();
    if (row < 0) return;

    let newData = dataList.getCellData(row, colid);
    let oldData = scwin.f_GetGridHidden(dataList, row, colid);

    if (pWinCloseTF == "T") {
        if (!scwin.f_CanGridPopup(dataList, colid, newData, oldData, colArray)) return false;
    }

    let paramObj = {};
    paramObj.pSelectID = "retrieveCommInfo_tpro";
    paramObj.pCode = newData;
    paramObj.pWinCloseTF = pWinCloseTF;
    paramObj.pAllSearchTF = pAllSearchTF;
    paramObj.pWtitleSearch = "품명조회,품명코드/품명";

    // TODO: cfCommonPopUpEx 팝업 호출 - WebSquare 팝업 방식으로 전환 필요
    let rtnList = $c.gus.cfCommonPopUpEx(paramObj);
    await scwin.f_SetGridReturnValue(rtnList, dataList, row, colArray);
};

scwin.f_copCoClntGridPopUp = async function(dataList, pWinCloseTF, pAllSearchTF, colid, colArray) {
    let row = dataList.getRowPosition();
    if (row < 0) return;

    let newData = dataList.getCellData(row, colid);
    let oldData = scwin.f_GetGridHidden(dataList, row, colid);

    if (pWinCloseTF == "T") {
        if (!scwin.f_CanGridPopup(dataList, colid, newData, oldData, colArray)) return false;
    }

    let paramObj = {};
    paramObj.pSelectID = "retrieveCoopList_tpro";
    paramObj.pCode = newData;
    paramObj.pWinCloseTF = pWinCloseTF;
    paramObj.pAllSearchTF = pAllSearchTF;
    paramObj.pWtitleSearch = "협력업체조회,협력업체 거래처번호/협력업체명";

    // TODO: cfCommonPopUpEx 팝업 호출 - WebSquare 팝업 방식으로 전환 필요
    let rtnList = $c.gus.cfCommonPopUpEx(paramObj);
    await scwin.f_SetGridReturnValue(rtnList, dataList, row, colArray);
};

scwin.f_ChangeGridPopupBtn = function(grid, colid) {
    if (grid == null || $c.gus.cfIsNull(colid)) return;
    // TODO: WebSquare gridView에서는 UrlImages 동적 변경 미지원
};

scwin.f_SetGridReturnValue = async function(rtnList, dataList, row, colArr, actionAfterSuccess) {
    try {
        if (dataList == null) throw "데이터셋이 정의 되지 않았습니다.";
        if (colArr == null) throw "컬럼이 정의 되지 않았습니다.";

        if (row == null) row = dataList.getRowPosition();
        if (row < 0) throw "데이터셋의 현재 행이 정의 되지 않았습니다.";

        if (rtnList == null) {
            scwin.f_ClearGridColumn(dataList, row, colArr);
        } else if (rtnList[0] == "N/A") {
            scwin.f_RedoGridColumn(dataList, row, colArr);
        } else {
            scwin.f_SetGridColumn(dataList, row, colArr, rtnList);
            if (actionAfterSuccess != null) eval(actionAfterSuccess);
        }

        return;
    } catch (e) {
        await $c.gus.cfAlertMsg(e);
    }
};

scwin.f_ClearGridColumn = function(dataList, row, col) {
    if (row < 0) return false;

    if (scwin.f_IsArray(col)) {
        for (let i = 0; i < col.length; i++) {
            scwin.f_ClearGridColumn(dataList, row, col[i]);
        }
    } else {
        if (col == null) col = "";
        dataList.setCellData(row, col, "");
        dataList.setAttribute(col, "");
    }
};

scwin.f_SetGridColumn = function(dataList, row, col, val) {
    if (row < 0) return false;

    if (scwin.f_IsArray(col)) {
        for (let i = 0; i < col.length; i++) {
            scwin.f_SetGridColumn(dataList, row, col[i], (val[i] == null ? "" : val[i]));
        }
    } else {
        if (col == null) col = "";
        if (val == null) val = "";
        dataList.setCellData(row, col, val);
        dataList.setAttribute(col, val);
    }
};

scwin.f_RedoGridColumn = function(dataList, row, col) {
    if (row < 0) return false;

    if (scwin.f_IsArray(col)) {
        for (let i = 0; i < col.length; i++) {
            scwin.f_RedoGridColumn(dataList, row, col[i]);
        }
    } else {
        dataList.setCellData(row, col, scwin.f_GetGridHidden(dataList, row, col));
    }
};

scwin.f_GetGridHidden = function(dataList, row, colid) {
    if (row < 0) return "";

    if (colid == null) return "";
    if (dataList.getAttribute(colid) == null) return "";

    return dataList.getAttribute(colid);
};

scwin.f_GetGridColumns = function(grid) {
    try {
        if (grid == null) throw "그리드가 정의되지 않았습니다.";

        let rtnArray = [];
        let colIds = grid.getColumnIDs();
        if (colIds != null) {
            for (let i = 0; i < colIds.length; i++) {
                rtnArray.push(colIds[i]);
            }
        }

        if (rtnArray.length == 0) {
            return null;
        } else {
            return rtnArray;
        }
    } catch (e) {
        // TODO: 동기 함수 내 에러 처리
    }
};

scwin.f_GetColumnNames_dl = function(dataList) {
    try {
        if (dataList == null) throw "데이터셋이 정의되지 않았습니다.";

        let colIds = dataList.getColumnIDs();
        if (colIds == null || colIds.length == 0) return null;

        return colIds;
    } catch (e) {
        // TODO: 동기 함수 내 에러 처리
    }
};

scwin.f_CanGridPopup = function(dataList, colid, newData, oldData, colArray) {
    let row = dataList.getRowPosition();

    if (row < 0) return false;

    if (newData == null) newData = "";
    if (oldData == null) oldData = "";

    if ($c.gus.cfIsNull(newData)) {
        scwin.f_ClearGridColumn(dataList, row, colArray);
        return false;
    }
    if (newData == oldData) return false;

    return true;
};

scwin.f_ToggleGridColumn = function(mode, grid, column, prop) {
    if (grid == null || column == null) return;

    if (scwin.f_IsArray(column)) {
        for (let i = 0; i < column.length; i++) {
            scwin.f_ToggleGridColumn(mode, grid, column[i], prop);
        }
    } else {
        if (!mode) {
            grid.setColumnReadOnly(column, true);
        } else {
            grid.setColumnReadOnly(column, false);
        }
    }
};

scwin.f_IsBetween = function(value, rangeStart, rangeEnd) {
    return (value >= rangeStart && value <= rangeEnd);
};

scwin.f_CopyDataRow = async function(sourceDataset, targetDataset, sourceRow, targetRow, sourceColumns, targetColumns, actionAfterRowAdded) {
    try {
        if (sourceDataset == null) throw "원본 데이터셋이 정의되지 않았습니다.";
        if (targetDataset == null) throw "대상 데이터셋이 정의되지 않았습니다.";

        if (sourceColumns == null) sourceColumns = scwin.f_GetColumnNames_dl(sourceDataset);
        if (targetColumns == null) targetColumns = sourceColumns;
        if (sourceRow == null) sourceRow = sourceDataset.getRowPosition();
        if (targetRow == null) targetRow = scwin.f_AddRowEx(targetDataset);

        for (let i = 0; i < sourceColumns.length; i++) {
            if ($c.gus.cfIsNull(sourceColumns[i]) || $c.gus.cfIsNull(targetColumns[i])) continue;
            let val = sourceDataset.getCellData(sourceRow, sourceColumns[i]);
            targetDataset.setCellData(targetRow, targetColumns[i], val);
            if (actionAfterRowAdded != null) eval(actionAfterRowAdded);
        }
        return targetRow;
    } catch (e) {
        await $c.gus.cfAlertMsg("[f_CopyDataRow]" + e);
    }
};

scwin.f_AddRowEx = function(dataList) {
    let newRow = dataList.insertRow();
    return newRow;
};

scwin.f_IsArray = function(inObj) {
    return (inObj instanceof Array);
};

scwin.f_IsUpdated = function(dataSet) {
    if (dataSet == null) return false;
    if (scwin.f_IsArray(dataSet)) {
        for (let i = 0; i < dataSet.length; i++) {
            if (scwin.f_IsUpdated(dataSet[i])) return true;
        }
    } else {
        if (dataSet.getUpdatedIndex().length > 0) return true;
    }
    return false;
};

scwin.f_ToggleObj = function(mode, obj) {
    if ($c.gus.cfIsNull(obj)) return;

    if (scwin.f_IsArray(obj)) {
        for (let i = 0; i < obj.length; i++) {
            (mode == true) ? $c.gus.cfEnableObjects(obj[i]) : $c.gus.cfDisableObjects(obj[i]);
        }
    } else {
        (mode == true) ? $c.gus.cfEnableObjects(obj) : $c.gus.cfDisableObjects(obj);
    }
};

scwin.f_ToggleImg = function(mode, obj) {
    if ($c.gus.cfIsNull(obj)) return;

    if (scwin.f_IsArray(obj)) {
        for (let i = 0; i < obj.length; i++) {
            scwin.f_ToggleImg(mode, obj[i]);
        }
    } else {
        scwin.f_ToggleObj(mode, obj);
    }
};

scwin.f_close = function() {
    $c.win.closePopup();
};

scwin.sbm_retrieve_submitdone = async function(e) {
    let rowCnt = ds_master.getRowCount();

    if (rowCnt == 0) {
        if (scwin.createFlag) {
            scwin.createFlag = false;
        } else {
            await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
        }
    }

    if (scwin.saveRow > 0) {
        let adjustedRow = scwin.saveRow;
        if (adjustedRow >= ds_master.getRowCount()) {
            adjustedRow = ds_master.getRowCount() - 1;
        }
        if (adjustedRow >= 0) {
            ds_master.setRowPosition(adjustedRow);
        }
        scwin.saveRow = 0;
    }

    spa_totalRows.setValue(rowCnt);
};

scwin.sbm_retrieve_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.sbm_retrieveDtl_submitdone = function(e) {
    let rowCnt = ds_detail.getRowCount();
    if (rowCnt == 0) return;

    spa_totalRowsDtl.setValue(rowCnt);
};

scwin.sbm_retrieveDtl_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

